1	/**
2	 * Parlour custom API routes.
3	 *
4	 * Contributed to the Oculus via supportKit.routes.
5	 * Provides endpoints for the Parlour page:
6	 *   GET  /api/parlour/roles           — list all system roles
7	 *   GET  /api/parlour/conversations   — list conversations for a role
8	 *   POST /api/parlour/create          — create a conversation
9	 *   POST /api/parlour/turn            — take a turn (SSE streaming)
10	 *
11	 * No Oculus types are imported — the Oculus duck-types the supportKit
12	 * via `as OculusKit`. Route handlers receive Hono Context objects.
13	 */
14	
15	import type { Context } from 'hono';
16	import { streamSSE } from 'hono/streaming';
17	import { guild } from '@shardworks/nexus-core';
18	import type { LoomApi } from '@shardworks/loom-apparatus';
19	import type { ParlourApi } from './types.ts';
20	
21	// ── Type stubs ────────────────────────────────────────────────────────
22	
23	/** Duck-typed RouteContribution — no import from Oculus needed. */
24	interface RouteContribution {
25	  method: string;
26	  path: string;
27	  handler: (c: Context) => Response | Promise<Response>;
28	}
29	
30	// ── Helpers ───────────────────────────────────────────────────────────
31	
32	/**
33	 * Determine the cwd for a new conversation.
34	 * If codexName is provided and the codexes apparatus is available,
35	 * opens a draft worktree and returns its path.
36	 * Otherwise falls back to guild().home.
37	 */
38	async function resolveCwd(codexName?: string): Promise<string> {
39	  if (codexName) {
40	    try {
41	      // Conditionally access the codexes apparatus
42	      const scriptorium = guild().apparatus<{
43	        openDraft(req: { codexName: string }): Promise<{ path: string }>;
44	      }>('codexes');
45	      const draft = await scriptorium.openDraft({ codexName });
46	      return draft.path;
47	    } catch {
48	      // Codexes apparatus not installed or failed — fall back to guild home
49	    }
50	  }
51	  return guild().home;
52	}
53	
54	// ── Route handlers ────────────────────────────────────────────────────
55	
56	/** GET /api/parlour/roles — list all system roles */
57	function rolesRoute(): RouteContribution {
58	  return {
59	    method: 'GET',
60	    path: '/api/parlour/roles',
61	    handler: (c: Context) => {
62	      const loom = guild().apparatus<LoomApi>('loom');
63	      const roles = loom.listRoles();
64	      return c.json(roles);
65	    },
66	  };
67	}
68	
69	/** GET /api/parlour/conversations — list conversations for a role */
70	function conversationsRoute(): RouteContribution {
71	  return {
72	    method: 'GET',
73	    path: '/api/parlour/conversations',
74	    handler: async (c: Context) => {
75	      const role = c.req.query('role');
76	      if (!role) {
77	        return c.json({ error: 'Missing required query param: role' }, 400);
78	      }
79	      const status = (c.req.query('status') as 'active' | 'concluded' | 'abandoned') ?? 'active';
80	
81	      const parlour = guild().apparatus<ParlourApi>('parlour');
82	      const allConvs = await parlour.list({ status, kind: 'consult', limit: 50 });
83	
84	      // Filter to conversations that have a participant with this role name
85	      const filtered = allConvs.filter((conv) =>
86	        conv.participants.some((p) => p.name === role),
87	      );
88	
89	      // Determine display title for each conversation
90	      const results = await Promise.all(
91	        filtered.map(async (conv) => {
92	          let title: string;
93	
94	          if (conv.topic && conv.topic.trim().length > 0) {
95	            title = conv.topic;
96	          } else {
97	            // Look for first human message
98	            const detail = await parlour.show(conv.id);
99	            const humanTurn = detail?.turns.find(
100	              (t) => t.sessionId === null && t.message !== null,
101	            );
102	
103	            if (humanTurn?.message) {
104	              title = humanTurn.message.length > 60
105	                ? humanTurn.message.slice(0, 60) + '…'
106	                : humanTurn.message;
107	            } else {
108	              // Fall back to formatted date
109	              title = new Date(conv.createdAt).toLocaleString();
110	            }
111	          }
112	
113	          return {
114	            id: conv.id,
115	            title,
116	            createdAt: conv.createdAt,
117	            turnCount: conv.turnCount,
118	            totalCostUsd: conv.totalCostUsd,
119	          };
120	        }),
121	      );
122	
123	      return c.json(results);
124	    },
125	  };
126	}
127	
128	/** POST /api/parlour/create — create a new consult conversation */
129	function createRoute(): RouteContribution {
130	  return {
131	    method: 'POST',
132	    path: '/api/parlour/create',
133	    handler: async (c: Context) => {
134	      const body = await c.req.json() as { role?: string; codexName?: string };
135	      const { role, codexName } = body;
136	
137	      if (!role) {
138	        return c.json({ error: 'Missing required field: role' }, 400);
139	      }
140	
141	      const cwd = await resolveCwd(codexName);
142	      const parlour = guild().apparatus<ParlourApi>('parlour');
143	
144	      const result = await parlour.create({
145	        kind: 'consult',
146	        participants: [
147	          { kind: 'human', name: 'User' },
148	          { kind: 'anima', name: role },
149	        ],
150	        cwd,
151	      });
152	
153	      return c.json({
154	        conversationId: result.conversationId,
155	        participants: result.participants,
156	      });
157	    },
158	  };
159	}
160	
161	/** POST /api/parlour/turn — take a turn with SSE streaming */
162	function turnRoute(): RouteContribution {
163	  return {
164	    method: 'POST',
165	    path: '/api/parlour/turn',
166	    handler: async (c: Context) => {
167	      // Parse and validate body BEFORE entering the SSE stream so we can
168	      // return proper HTTP 400 responses for invalid input.
169	      let body: {
170	        conversationId?: string;
171	        role?: string;
172	        message?: string;
173	        codexName?: string;
174	      };
175	
176	      try {
177	        body = await c.req.json() as typeof body;
178	      } catch {
179	        return c.json({ error: 'Invalid JSON body' }, 400);
180	      }
181	
182	      const { conversationId: reqConversationId, role, message, codexName } = body;
183	
184	      if (!reqConversationId && !role) {
185	        return c.json({ error: 'Either conversationId or role is required' }, 400);
186	      }
187	      if (!message || message.trim() === '') {
188	        return c.json({ error: 'message is required and must not be empty' }, 400);
189	      }
190	
191	      return streamSSE(c, async (stream) => {
192	        const parlour = guild().apparatus<ParlourApi>('parlour');
193	
194	        let conversationId: string;
195	        let humanParticipantId: string;
196	        let animaParticipantId: string;
197	
198	        try {
199	          if (reqConversationId) {
200	            // Use existing conversation
201	            conversationId = reqConversationId;
202	            const detail = await parlour.show(conversationId);
203	            if (!detail) {
204	              await stream.writeSSE({
205	                event: 'error',
206	                data: JSON.stringify({ error: `Conversation "${conversationId}" not found` }),
207	              });
208	              return;
209	            }
210	            const human = detail.participants.find((p) => p.kind === 'human');
211	            const anima = detail.participants.find((p) => p.kind === 'anima');
212	            if (!human || !anima) {
213	              await stream.writeSSE({
214	                event: 'error',
215	                data: JSON.stringify({ error: 'Conversation missing human or anima participant' }),
216	              });
217	              return;
218	            }
219	            humanParticipantId = human.id;
220	            animaParticipantId = anima.id;
221	          } else {
222	            // Create new conversation lazily
223	            const cwd = await resolveCwd(codexName);
224	            const created = await parlour.create({
225	              kind: 'consult',
226	              participants: [
227	                { kind: 'human', name: 'User' },
228	                { kind: 'anima', name: role! },
229	              ],
230	              cwd,
231	            });
232	
233	            conversationId = created.conversationId;
234	            const human = created.participants.find((p) => p.kind === 'human');
235	            const anima = created.participants.find((p) => p.kind === 'anima');
236	            humanParticipantId = human!.id;
237	            animaParticipantId = anima!.id;
238	
239	            // Emit conversation_created event
240	            await stream.writeSSE({
241	              event: 'conversation_created',
242	              data: JSON.stringify({
243	                conversationId,
244	                participants: created.participants,
245	              }),
246	            });
247	          }
248	
249	          // Take human turn
250	          await parlour.takeTurn({
251	            conversationId,
252	            participantId: humanParticipantId,
253	            message: message.trim(),
254	          });
255	
256	          // Take anima turn with streaming
257	          const { chunks, result } = parlour.takeTurnStreaming({
258	            conversationId,
259	            participantId: animaParticipantId,
260	          });
261	
262	          // Stream chunks to client
263	          for await (const chunk of chunks) {
264	            await stream.writeSSE({
265	              event: 'chunk',
266	              data: JSON.stringify(chunk),
267	            });
268	          }
269	
270	          // Await result to ensure turn recording completes
271	          await result;
272	        } catch (err: unknown) {
273	          const errMessage = err instanceof Error ? err.message : String(err);
274	          await stream.writeSSE({
275	            event: 'error',
276	            data: JSON.stringify({ error: errMessage }),
277	          });
278	        }
279	      });
280	    },
281	  };
282	}
283	
284	// ── Exported routes array ─────────────────────────────────────────────
285	
