1	/**
2	 * The Parlour — multi-turn conversation management apparatus.
3	 *
4	 * Manages two kinds of conversation:
5	 * - consult: a human talks to an anima
6	 * - convene: multiple animas hold a structured dialogue
7	 *
8	 * The Parlour orchestrates turns — it decides when and for whom to call
9	 * The Animator, and tracks conversation state in The Stacks. It does not
10	 * launch sessions itself (delegates to The Animator) or assemble prompts
11	 * (delegates to The Loom).
12	 *
13	 * See: docs/architecture/apparatus/parlour.md
14	 */
15	
16	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
17	import { guild, generateId } from '@shardworks/nexus-core';
18	import type { StacksApi, Book, ReadOnlyBook, WhereCondition } from '@shardworks/stacks-apparatus';
19	import type { AnimatorApi, SessionResult, SessionChunk, SessionDoc } from '@shardworks/animator-apparatus';
20	import type { LoomApi } from '@shardworks/loom-apparatus';
21	
22	import type {
23	  ParlourApi,
24	  ConversationDoc,
25	  TurnDoc,
26	  ParticipantRecord,
27	  Participant,
28	  CreateConversationRequest,
29	  CreateConversationResult,
30	  TakeTurnRequest,
31	  TurnResult,
32	  ConversationChunk,
33	  ConversationSummary,
34	  ConversationDetail,
35	  TurnSummary,
36	  ListConversationsOptions,
37	} from './types.ts';
38	
39	import { conversationList, conversationShow, conversationEnd } from './tools/index.ts';
40	import { parlourRoutes } from './routes.ts';
41	
42	// ── Helpers ──────────────────────────────────────────────────────────
43	
44	/**
45	 * Count anima turns in the conversation (for turn limit enforcement).
46	 * Human turns do not count toward the turn limit.
47	 */
48	async function countAnimaTurns(
49	  turns: ReadOnlyBook<TurnDoc>,
50	  conversationId: string,
51	): Promise<number> {
52	  return turns.count([
53	    ['conversationId', '=', conversationId],
54	    ['participantKind', '=', 'anima'],
55	  ]);
56	}
57	
58	/**
59	 * Count all turns in the conversation (for turnNumber assignment).
60	 */
61	async function countAllTurns(
62	  turns: ReadOnlyBook<TurnDoc>,
63	  conversationId: string,
64	): Promise<number> {
65	  return turns.count([
66	    ['conversationId', '=', conversationId],
67	  ]);
68	}
69	
70	/**
71	 * Get the most recent turn for a specific participant.
72	 */
73	async function getLastTurnForParticipant(
74	  turns: ReadOnlyBook<TurnDoc>,
75	  conversationId: string,
76	  participantId: string,
77	): Promise<TurnDoc | null> {
78	  const results = await turns.find({
79	    where: [
80	      ['conversationId', '=', conversationId],
81	      ['participantId', '=', participantId],
82	    ],
83	    orderBy: ['turnNumber', 'desc'],
84	    limit: 1,
85	  });
86	  return results[0] ?? null;
87	}
88	
89	/**
90	 * Get turns since a given turn number (exclusive), ordered ascending.
91	 */
92	async function getTurnsSince(
93	  turns: ReadOnlyBook<TurnDoc>,
94	  conversationId: string,
95	  afterTurnNumber: number,
96	): Promise<TurnDoc[]> {
97	  return turns.find({
98	    where: [
99	      ['conversationId', '=', conversationId],
100	      ['turnNumber', '>', afterTurnNumber],
101	    ],
102	    orderBy: ['turnNumber', 'asc'],
103	  });
104	}
105	
106	/**
107	 * Get all turns for a conversation, ordered by turnNumber ascending.
108	 */
109	async function getAllTurns(
110	  turns: ReadOnlyBook<TurnDoc>,
111	  conversationId: string,
112	): Promise<TurnDoc[]> {
113	  return turns.find({
114	    where: [
115	      ['conversationId', '=', conversationId],
116	    ],
117	    orderBy: ['turnNumber', 'asc'],
118	  });
119	}
120	
121	/**
122	 * Map ParticipantRecord[] to Participant[] (public projection).
123	 */
124	function toParticipants(records: ParticipantRecord[]): Participant[] {
125	  return records.map((r) => ({
126	    id: r.id,
127	    name: r.name,
128	    kind: r.kind,
129	  }));
130	}
131	
132	/**
133	 * Assemble the inter-turn message for a consult conversation.
134	 *
135	 * For consult, the pattern is simple: the human's message from the
136	 * TakeTurnRequest is passed directly as the prompt. If no message
137	 * is provided, the conversation topic is used as fallback (first turn).
138	 */
139	function assembleConsultMessage(
140	  request: TakeTurnRequest,
141	  conversation: ConversationDoc,
142	  isFirstTurn: boolean,
143	): string | undefined {
144	  if (request.message) return request.message;
145	  if (isFirstTurn && conversation.topic) return conversation.topic;
146	  return undefined;
147	}
148	
149	/**
150	 * Assemble the inter-turn message for a convene conversation.
151	 *
152	 * For convene, each participant needs to see what other participants said
153	 * since their last turn. This requires reading session transcripts, which
154	 * depends on session record artifacts that the Animator MVP does not produce.
155	 *
156	 * At MVP, this uses the human-readable messages stored in turn records,
157	 * which are adequate for human turns but cannot capture anima responses
158	 * (the Animator does not expose transcript text). Anima contributions
159	 * fall back to a placeholder.
160	 *
161	 * See: parlour-implementation-tracker.md § Gap #1
162	 */
163	async function assembleConveneMessage(
164	  turns: ReadOnlyBook<TurnDoc>,
165	  conversation: ConversationDoc,
166	  participantId: string,
167	  isFirstTurn: boolean,
168	): Promise<string | undefined> {
169	  if (isFirstTurn && conversation.topic) return conversation.topic;
170	
171	  // Get this participant's last turn to find intervening turns
172	  const lastTurn = await getLastTurnForParticipant(
173	    turns,
174	    conversation.id,
175	    participantId,
176	  );
177	
178	  if (!lastTurn) {
179	    // Never taken a turn — use topic
180	    return conversation.topic ?? undefined;
181	  }
182	
183	  // Get all turns since this participant's last turn
184	  const intervening = await getTurnsSince(
185	    turns,
186	    conversation.id,
187	    lastTurn.turnNumber,
188	  );
189	
190	  if (intervening.length === 0) return undefined;
191	
192	  // Assemble messages from other participants
193	  const lines: string[] = [];
194	  for (const turn of intervening) {
195	    if (turn.participantId === participantId) continue;
196	    if (turn.participantKind === 'human' && turn.message) {
197	      lines.push(`[${turn.participantName}]: ${turn.message}`);
198	    } else if (turn.participantKind === 'anima') {
199	      // Cannot extract anima response — Animator MVP has no transcript text.
200	      // Placeholder until session record artifacts or response capture is available.
201	      lines.push(`[${turn.participantName}]: [response not available]`);
202	    }
203	  }
204	
205	  return lines.length > 0 ? lines.join('\n\n') : undefined;
206	}
207	
208	// ── Apparatus factory ────────────────────────────────────────────────
209	
210	/**
211	 * Create the Parlour apparatus plugin.
212	 *
213	 * Returns a Plugin with:
214	 * - `requires: ['stacks', 'animator', 'loom']` — conversation orchestration
215	 * - `provides: ParlourApi` — the conversation management API
216	 * - `supportKit` — contributes `conversations` + `turns` books + management tools
217	 */
218	export function createParlour(): Plugin {
219	  let conversations: Book<ConversationDoc>;
220	  let turns: Book<TurnDoc>;
221	  let sessions: ReadOnlyBook<SessionDoc>;
222	
223	  const api: ParlourApi = {
224	    async create(request: CreateConversationRequest): Promise<CreateConversationResult> {
225	      const conversationId = generateId('conv');
226	
227	      // Build participant records
228	      const participants: ParticipantRecord[] = request.participants.map((decl) => ({
229	        id: generateId('part'),
230	        kind: decl.kind,
231	        name: decl.name,
232	        animaId: null, // No Roster yet — leave null at MVP
233	        providerSessionId: null,
234	      }));
235	
236	      // Write conversation document
237	      const doc: ConversationDoc = {
238	        id: conversationId,
239	        status: 'active',
240	        kind: request.kind,
241	        topic: request.topic ?? null,
242	        turnLimit: request.turnLimit ?? null,
243	        createdAt: new Date().toISOString(),
244	        endedAt: null,
245	        eventId: request.eventId ?? null,
246	        participants,
247	        cwd: request.cwd,
248	      };
249	
250	      await conversations.put(doc);
251	
252	      return {
253	        conversationId,
254	        participants: toParticipants(participants),
255	      };
256	    },
257	
258	    async takeTurn(request: TakeTurnRequest): Promise<TurnResult> {
259	      // 1. Read conversation state
260	      const conv = await conversations.get(request.conversationId);
261	      if (!conv) {
262	        throw new Error(`Conversation "${request.conversationId}" not found.`);
263	      }
264	      if (conv.status !== 'active') {
265	        throw new Error(
266	          `Conversation "${request.conversationId}" is ${conv.status}, not active.`,
267	        );
268	      }
269	
270	      // Find the participant
271	      const participant = conv.participants.find((p) => p.id === request.participantId);
272	      if (!participant) {
273	        throw new Error(
274	          `Participant "${request.participantId}" not found in conversation "${request.conversationId}".`,
275	        );
276	      }
277	
278	      // 2. Determine turn number
279	      const totalTurns = await countAllTurns(turns, conv.id);
280	      const turnNumber = totalTurns + 1;
281	
282	      // 3. Check turn limit (anima turns only)
283	      if (participant.kind === 'anima' && conv.turnLimit !== null) {
284	        const animaTurns = await countAnimaTurns(turns, conv.id);
285	        if (animaTurns >= conv.turnLimit) {
286	          throw new Error(
287	            `Conversation "${conv.id}" has reached its turn limit of ${conv.turnLimit}.`,
288	          );
289	        }
290	      }
291	
292	      const startedAt = new Date().toISOString();
293	
294	      if (participant.kind === 'human') {
295	        // Human turn — record the message, no session launched
296	        const turnId = generateId('turn', 6);
297	        await turns.put({
298	          id: turnId,
299	          conversationId: conv.id,
300	          turnNumber,
301	          participantId: participant.id,
302	          participantName: participant.name,
303	          participantKind: 'human',
304	          message: request.message ?? null,
305	          sessionId: null,
306	          startedAt,
307	          endedAt: new Date().toISOString(),
308	        });
309	
310	        return {
311	          sessionResult: null,
312	          turnNumber,
313	          conversationActive: true,
314	        };
315	      }
316	
317	      // Anima turn — weave context and call the Animator
318	      const loom = guild().apparatus<LoomApi>('loom');
319	      const animator = guild().apparatus<AnimatorApi>('animator');
320	
321	      // Determine if this is the participant's first turn
322	      const lastTurn = await getLastTurnForParticipant(turns, conv.id, participant.id);
323	      const isFirstTurn = lastTurn === null;
324	
325	      // Assemble the message for this turn
326	      let message: string | undefined;
327	      if (conv.kind === 'consult') {
328	        message = assembleConsultMessage(request, conv, isFirstTurn);
329	      } else {
330	        message = await assembleConveneMessage(turns, conv, participant.id, isFirstTurn);
331	      }
332	
333	      // Weave anima context via The Loom
334	      const context = await loom.weave({ role: undefined });
335	
336	      // Call The Animator
337	      const { result: resultPromise } = animator.animate({
338	        context,
339	        prompt: message,
340	        cwd: conv.cwd,
341	        conversationId: participant.providerSessionId ?? undefined,
342	        metadata: {
343	          trigger: 'parlour',
344	          conversationId: conv.id,
345	          turnNumber,
346	          participantId: participant.id,
347	        },
348	      });
349	
350	      const sessionResult = await resultPromise;
351	
352	      // Update participant's providerSessionId for --resume
353	      const updatedParticipants = conv.participants.map((p) =>
354	        p.id === participant.id
355	          ? { ...p, providerSessionId: sessionResult.providerSessionId ?? p.providerSessionId }
356	          : p,
357	      );
358	      await conversations.patch(conv.id, { participants: updatedParticipants });
359	
360	      // Record the turn
361	      const turnId = generateId('turn', 6);
362	      await turns.put({
363	        id: turnId,
364	        conversationId: conv.id,
365	        turnNumber,
366	        participantId: participant.id,
367	        participantName: participant.name,
368	        participantKind: 'anima',
369	        message: message ?? null,
370	        sessionId: sessionResult.id,
371	        startedAt,
372	        endedAt: new Date().toISOString(),
373	      });
374	
375	      // Check if turn limit reached → auto-conclude
376	      let conversationActive = true;
377	      if (conv.turnLimit !== null) {
378	        const animaTurns = await countAnimaTurns(turns, conv.id);
379	        if (animaTurns >= conv.turnLimit) {
380	          await this.end(conv.id, 'concluded');
381	          conversationActive = false;
382	        }
383	      }
384	
385	      return {
386	        sessionResult,
387	        turnNumber,
388	        conversationActive,
389	      };
390	    },
391	
392	    takeTurnStreaming(request: TakeTurnRequest): {
393	      chunks: AsyncIterable<ConversationChunk>;
394	      result: Promise<TurnResult>;
395	    } {
396	      type HumanResolved = { kind: 'human'; turnResult: TurnResult };
397	      type AnimaResolved = {
398	        kind: 'anima';
399	        animatorChunks: AsyncIterable<SessionChunk>;
400	        animatorResult: Promise<SessionResult>;
401	        conv: ConversationDoc;
402	        participant: ParticipantRecord;
403	        turnNumber: number;
404	        startedAt: string;
405	        message: string | undefined;
406	      };
407	      type StreamResolved = HumanResolved | AnimaResolved;
408	
409	      // Read conversation state and launch the turn.
410	      // We need to return synchronously, so wrap the async flow.
411	      const deferred: Promise<StreamResolved> = (async (): Promise<StreamResolved> => {
412	        // 1. Read conversation state
413	        const conv = await conversations.get(request.conversationId);
414	        if (!conv) {
415	          throw new Error(`Conversation "${request.conversationId}" not found.`);
416	        }
417	        if (conv.status !== 'active') {
418	          throw new Error(
419	            `Conversation "${request.conversationId}" is ${conv.status}, not active.`,
420	          );
421	        }
422	
423	        // Find the participant
424	        const participant = conv.participants.find((p) => p.id === request.participantId);
425	        if (!participant) {
426	          throw new Error(
427	            `Participant "${request.participantId}" not found in conversation "${request.conversationId}".`,
428	          );
429	        }
430	
431	        // Human turns don't stream — delegate to non-streaming path
432	        if (participant.kind === 'human') {
433	          const turnResult = await this.takeTurn(request);
434	          return { kind: 'human', turnResult };
435	        }
436	
437	        // 2. Determine turn number
438	        const totalTurns = await countAllTurns(turns, conv.id);
439	        const turnNumber = totalTurns + 1;
440	
441	        // 3. Check turn limit
442	        if (conv.turnLimit !== null) {
443	          const animaTurns = await countAnimaTurns(turns, conv.id);
444	          if (animaTurns >= conv.turnLimit) {
445	            throw new Error(
446	              `Conversation "${conv.id}" has reached its turn limit of ${conv.turnLimit}.`,
447	            );
448	          }
449	        }
450	
451	        const startedAt = new Date().toISOString();
452	
453	        const loom = guild().apparatus<LoomApi>('loom');
454	        const animator = guild().apparatus<AnimatorApi>('animator');
455	
456	        // Determine if first turn
457	        const lastTurn = await getLastTurnForParticipant(turns, conv.id, participant.id);
458	        const isFirstTurn = lastTurn === null;
459	
460	        // Assemble message
461	        let message: string | undefined;
462	        if (conv.kind === 'consult') {
463	          message = assembleConsultMessage(request, conv, isFirstTurn);
464	        } else {
465	          message = await assembleConveneMessage(turns, conv, participant.id, isFirstTurn);
466	        }
467	
468	        // Weave + animate with streaming
469	        const context = await loom.weave({ role: undefined });
470	        const handle = animator.animate({
471	          context,
472	          prompt: message,
473	          cwd: conv.cwd,
474	          conversationId: participant.providerSessionId ?? undefined,
475	          metadata: {
476	            trigger: 'parlour',
477	            conversationId: conv.id,
478	            turnNumber,
479	            participantId: participant.id,
480	          },
481	          streaming: true,
482	        });
483	
484	        return {
485	          kind: 'anima',
486	          animatorChunks: handle.chunks,
487	          animatorResult: handle.result,
488	          conv,
489	          participant,
490	          turnNumber,
491	          startedAt,
492	          message,
493	        };
494	      })();
495	
496	      async function* streamChunks(): AsyncIterable<ConversationChunk> {
497	        const resolved = await deferred;
498	        // Human turn — no chunks
499	        if (resolved.kind === 'human') return;
500	
501	        const { animatorChunks, animatorResult } = resolved;
502	
503	        // Pipe through Animator chunks
504	        yield* animatorChunks;
505	
506	        // Wait for final result to emit turn_complete
507	        const sessionResult = await animatorResult;
508	        yield {
509	          type: 'turn_complete' as const,
510	          turnNumber: resolved.turnNumber,
511	          costUsd: sessionResult.costUsd,
512	        };
513	      }
514	
515	      const result = (async (): Promise<TurnResult> => {
516	        const resolved = await deferred;
517	
518	        // Human turn — already handled
519	        if (resolved.kind === 'human') return resolved.turnResult;
520	
521	        const { animatorResult, conv, participant, turnNumber, startedAt, message } = resolved;
522	        const sessionResult = await animatorResult;
523	
524	        // Update providerSessionId
525	        const updatedParticipants = conv.participants.map((p) =>
526	          p.id === participant.id
527	            ? { ...p, providerSessionId: sessionResult.providerSessionId ?? p.providerSessionId }
528	            : p,
529	        );
530	        await conversations.patch(conv.id, { participants: updatedParticipants });
531	
532	        // Record turn
533	        const turnId = generateId('turn', 6);
534	        await turns.put({
535	          id: turnId,
536	          conversationId: conv.id,
537	          turnNumber,
538	          participantId: participant.id,
539	          participantName: participant.name,
540	          participantKind: 'anima',
541	          message: message ?? null,
542	          sessionId: sessionResult.id,
543	          startedAt,
544	          endedAt: new Date().toISOString(),
545	        });
546	
547	        // Check turn limit
548	        let conversationActive = true;
549	        if (conv.turnLimit !== null) {
550	          const animaTurns = await countAnimaTurns(turns, conv.id);
551	          if (animaTurns >= conv.turnLimit) {
552	            await api.end(conv.id, 'concluded');
553	            conversationActive = false;
554	          }
555	        }
556	
557	        return { sessionResult, turnNumber, conversationActive };
558	      })();
559	
560	      return { chunks: streamChunks(), result };
561	    },
562	
563	    async nextParticipant(conversationId: string): Promise<Participant | null> {
564	      const conv = await conversations.get(conversationId);
565	      if (!conv || conv.status !== 'active') return null;
566	
567	      // Check turn limit
568	      if (conv.turnLimit !== null) {
569	        const animaTurns = await countAnimaTurns(turns, conv.id);
570	        if (animaTurns >= conv.turnLimit) return null;
571	      }
572	
573	      if (conv.kind === 'consult') {
574	        // For consult: always return the anima participant
575	        const anima = conv.participants.find((p) => p.kind === 'anima');
576	        if (!anima) return null;
577	        return { id: anima.id, name: anima.name, kind: anima.kind };
578	      }
579	
580	      // For convene: round-robin among all participants
581	      const totalTurns = await countAllTurns(turns, conv.id);
582	      const nextIndex = totalTurns % conv.participants.length;
583	      const next = conv.participants[nextIndex];
584	      return { id: next.id, name: next.name, kind: next.kind };
585	    },
586	
587	    async end(conversationId: string, reason?: 'concluded' | 'abandoned'): Promise<void> {
588	      const conv = await conversations.get(conversationId);
589	      if (!conv) {
590	        throw new Error(`Conversation "${conversationId}" not found.`);
591	      }
592	      // Idempotent — no error if already ended
593	      if (conv.status !== 'active') return;
594	
595	      await conversations.patch(conversationId, {
596	        status: reason ?? 'concluded',
597	        endedAt: new Date().toISOString(),
598	      });
599	    },
600	
601	    async list(options?: ListConversationsOptions): Promise<ConversationSummary[]> {
602	      const where: WhereCondition[] = [];
603	      if (options?.status) where.push(['status', '=', options.status]);
604	      if (options?.kind) where.push(['kind', '=', options.kind]);
605	
606	      const convs = await conversations.find({
607	        where: where.length > 0 ? where : undefined,
608	        orderBy: ['createdAt', 'desc'],
609	        limit: options?.limit ?? 20,
610	      });
611	
612	      // Build summaries with turn counts and cost aggregation
613	      const summaries: ConversationSummary[] = [];
614	      for (const conv of convs) {
615	        const convTurns = await getAllTurns(turns, conv.id);
616	        const sessionIds = convTurns
617	          .map((t) => t.sessionId)
618	          .filter((id): id is string => id !== null);
619	
620	        // Aggregate cost from session records
621	        let totalCostUsd = 0;
622	        for (const sessionId of sessionIds) {
623	          const session = await sessions.get(sessionId);
624	          if (session?.costUsd) totalCostUsd += session.costUsd;
625	        }
626	
627	        summaries.push({
628	          id: conv.id,
629	          status: conv.status,
630	          kind: conv.kind,
631	          topic: conv.topic,
632	          turnLimit: conv.turnLimit,
633	          createdAt: conv.createdAt,
634	          endedAt: conv.endedAt,
635	          participants: toParticipants(conv.participants),
636	          turnCount: convTurns.length,
637	          totalCostUsd,
638	        });
639	      }
640	
641	      return summaries;
642	    },
643	
644	    async show(conversationId: string): Promise<ConversationDetail | null> {
645	      const conv = await conversations.get(conversationId);
646	      if (!conv) return null;
647	
648	      const convTurns = await getAllTurns(turns, conv.id);
649	
650	      // Fetch session docs for all anima turns in one pass.
651	      // Used for both per-turn enrichment and aggregate cost.
652	      const sessionDocMap = new Map<string, Awaited<ReturnType<typeof sessions.get>>>();
653	      for (const t of convTurns) {
654	        if (t.sessionId !== null) {
655	          const session = await sessions.get(t.sessionId);
656	          sessionDocMap.set(t.sessionId, session);
657	        }
658	      }
659	
660	      // Aggregate cost across all anima turns
661	      let totalCostUsd = 0;
662	      for (const session of sessionDocMap.values()) {
663	        if (session?.costUsd) totalCostUsd += session.costUsd;
664	      }
665	
666	      // Build enriched turn summaries
667	      const turnSummaries: TurnSummary[] = convTurns.map((t) => {
668	        if (t.sessionId === null) {
669	          // Human turn — no session data
670	          return {
671	            sessionId: null,
672	            turnNumber: t.turnNumber,
673	            participant: t.participantName,
674	            message: t.message,
675	            startedAt: t.startedAt,
676	            endedAt: t.endedAt,
677	            output: null,
678	            costUsd: null,
679	            tokenUsage: null,
680	          };
681	        }
682	
683	        const session = sessionDocMap.get(t.sessionId);
684	        return {
685	          sessionId: t.sessionId,
686	          turnNumber: t.turnNumber,
687	          participant: t.participantName,
688	          message: t.message,
689	          startedAt: t.startedAt,
690	          endedAt: t.endedAt,
691	          output: session?.output ?? null,
692	          costUsd: session?.costUsd ?? null,
693	          tokenUsage: session?.tokenUsage ?? null,
694	        };
695	      });
696	
697	      return {
698	        id: conv.id,
699	        status: conv.status,
700	        kind: conv.kind,
701	        topic: conv.topic,
702	        turnLimit: conv.turnLimit,
703	        createdAt: conv.createdAt,
704	        endedAt: conv.endedAt,
705	        participants: toParticipants(conv.participants),
706	        turnCount: convTurns.length,
707	        totalCostUsd,
708	        turns: turnSummaries,
709	      };
710	    },
711	  };
712	
713	  return {
714	    apparatus: {
715	      requires: ['stacks', 'animator', 'loom'],
716	
717	      supportKit: {
718	        books: {
719	          conversations: {
720	            indexes: ['status', 'kind', 'createdAt'],
721	          },
722	          turns: {
723	            indexes: ['conversationId', 'turnNumber', 'participantId', 'participantKind'],
724	          },
725	        },
726	        tools: [conversationList, conversationShow, conversationEnd],
727	        pages: [
728	          { id: 'parlour', title: 'Parlour', dir: 'src/static/parlour' },
729	        ],
730	        routes: parlourRoutes,
731	      },
732	
733	      provides: api,
734	
735	      start(_ctx: StartupContext): void {
736	        const g = guild();
737	        const stacks = g.apparatus<StacksApi>('stacks');
738	        conversations = stacks.book<ConversationDoc>('parlour', 'conversations');
739	        turns = stacks.book<TurnDoc>('parlour', 'turns');
740	        sessions = stacks.readBook<SessionDoc>('animator', 'sessions');
741	      },
742	    },
743	  };
744	}
